    def __init__(self, key):
        self.key = key
        self.left = None
        self.right = None

def search(root, key):
    # Base case: root is None or key is at root
    if root is None or root.key == key:
        return root

    # Key is greater than root's key
    if key > root.key:
        return search(root.right, key)

    # Key is smaller than root's key
    return search(root.left, key)

# Time: O(h) where h is height
# Best: O(1) if found at root
# Worst: O(n) if skewed
# Avg: O(log n) if balanced

class Node:
    def __init__(self, key):
        self.key = key
        self.left = None
        self.right = None

def insert(root, key):
    # Base case: found empty position
    if root is None:
        return Node(key)

    # Duplicate values: go to right subtree
    if key > root.key:
        root.right = insert(root.right, key)
    else:
        root.left = insert(root.left, key)

    return root

# Usage: root = insert(None, 50)
#        root = insert(root, 30)
#        root = insert(root, 70)

# Time: O(h)
# Space: O(h) for recursion stack

class Node:
    def __init__(self, key):
        self.key = key
        self.left = None
        self.right = None

def delete(root, key):
    # Base case: key not found
    if root is None:
        return None

    # Search for node to delete
    if key > root.key:
        root.right = delete(root.right, key)
    elif key < root.key:
        root.left = delete(root.left, key)
    else:
        # Node found - handle three cases

        # Case 1 & 2: One child or no child
        if root.left is None:
            return root.right
        if root.right is None:
            return root.left

        # Case 3: Two children
        # Find in-order successor (minimum in right subtree)
        successor = minValueNode(root.right)
        root.key = successor.key
        root.right = delete(root.right, successor.key)

    return root

def minValueNode(node):
    current = node
    while current.left:
        current = current.left
    return current

# Time: O(h) for all cases
# Space: O(h) for recursion

class Node:
    def __init__(self, key):
        self.key = key
        self.left = None
        self.right = None

def isBalanced(root):
    return checkHeight(root) != -1

def checkHeight(node):
    # Base case: empty tree
    if node is None:
        return 0

    # Check left subtree height
    leftHeight = checkHeight(node.left)
    if leftHeight == -1:
        return -1  # Not balanced

    # Check right subtree height
    rightHeight = checkHeight(node.right)
    if rightHeight == -1:
        return -1  # Not balanced

    # Check balance at current node
    if abs(leftHeight - rightHeight) > 1:
        return -1

    # Return height of this node
    return max(leftHeight, rightHeight) + 1

# Time: O(n) - visits each node once
# Space: O(h) - recursion stack
